import { unstable_cache } from "next/cache";

export async function getAllProducts() {
  // Simulate database delay
  await new Promise(resolve => setTimeout(resolve, 100));

  return [
    { id: 1, name: "Laptop", price: 999, inStock: true },
    { id: 2, name: "Phone", price: 699, inStock: true },
    { id: 3, name: "Tablet", price: 499, inStock: false },
    { id: 4, name: "Headphones", price: 199, inStock: true },
    { id: 5, name: "Watch", price: 299, inStock: true },
  ];
}

/**
 * Cached wrapper around getAllProducts.
 * Uses the "products" cache tag so revalidateTag("products") busts this
 * across all views that depend on the same catalog data.
 */
export const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ["catalog-products"],
  { tags: ["products"] }
);

