import { revalidateTag } from "next/cache";
import { getCachedProducts } from "@/lib/db";

export default async function AdminCatalogPage() {
  async function syncCatalog(formData: FormData) {
    "use server";

    // Mark the catalog cache as stale — the next read of getCachedProducts
    // will re-execute, but this action returns immediately so the admin can
    // keep working even if the product list is briefly stale.
    revalidateTag("products");
  }

  const products = await getCachedProducts();

  return (
    <div style={{ maxWidth: 800, margin: "40px auto", fontFamily: "system-ui, sans-serif" }}>
      <header
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: 32,
        }}
      >
        <div>
          <h1 style={{ margin: 0, fontSize: 24 }}>Product Catalog</h1>
          <p style={{ margin: "4px 0 0", color: "#666", fontSize: 14 }}>
            {products.length} products
          </p>
        </div>

        <form action={syncCatalog}>
          <button
            type="submit"
            style={{
              padding: "8px 20px",
              fontSize: 14,
              fontWeight: 600,
              background: "#0052cc",
              color: "#fff",
              border: "none",
              borderRadius: 6,
              cursor: "pointer",
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </header>

      <table
        style={{
          width: "100%",
          borderCollapse: "collapse",
          fontSize: 14,
        }}
      >
        <thead>
          <tr style={{ textAlign: "left", borderBottom: "2px solid #e2e8f0" }}>
            <th style={{ padding: "10px 12px", fontWeight: 600, color: "#475569" }}>
              ID
            </th>
            <th style={{ padding: "10px 12px", fontWeight: 600, color: "#475569" }}>
              Name
            </th>
            <th style={{ padding: "10px 12px", fontWeight: 600, color: "#475569" }}>
              Price
            </th>
            <th style={{ padding: "10px 12px", fontWeight: 600, color: "#475569" }}>
              Status
            </th>
          </tr>
        </thead>
        <tbody>
          {products.map((product) => (
            <tr
              key={product.id}
              style={{ borderBottom: "1px solid #e2e8f0" }}
            >
              <td style={{ padding: "10px 12px", color: "#64748b" }}>
                {product.id}
              </td>
              <td style={{ padding: "10px 12px", fontWeight: 500 }}>
                {product.name}
              </td>
              <td style={{ padding: "10px 12px" }}>
                ${product.price}
              </td>
              <td style={{ padding: "10px 12px" }}>
                <span
                  style={{
                    display: "inline-block",
                    padding: "2px 10px",
                    borderRadius: 12,
                    fontSize: 12,
                    fontWeight: 600,
                    background: product.inStock ? "#dcfce7" : "#fef3c7",
                    color: product.inStock ? "#166534" : "#92400e",
                  }}
                >
                  {product.inStock ? "In stock" : "Out of stock"}
                </span>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

