import { revalidateTag } from "next/cache";
import { getCachedProducts } from "@/lib/db";

// Render on each request so the page always reads the latest cached data.
// The data itself is cached via getCachedProducts (tag: "products") to avoid
// re-querying on every request.
export const dynamic = "force-dynamic";
